input.command:
# Initialize the replica set via the localhost exception (no auth before first user)
kubectl exec -n mongodb mongodb-replica-0 -- mongosh --quiet --eval '
rs.initiate({
  _id: "mongodb-replica",
  members: [
    { _id: 0, host: "mongodb-replica-0.mongodb-replica-svc.mongodb.svc.cluster.local:27017" },
    { _id: 1, host: "mongodb-replica-1.mongodb-replica-svc.mongodb.svc.cluster.local:27017" },
    { _id: 2, host: "mongodb-replica-2.mongodb-replica-svc.mongodb.svc.cluster.local:27017" }
  ]
})
'

# Create admin user (using localhost exception — still no auth users yet)
kubectl exec -n mongodb mongodb-replica-0 -- mongosh --quiet --eval '
db = db.getSiblingDB("admin");
db.createUser({
  user: "admin-user",
  pwd: "admin123password",
  roles: [
    { role: "root", db: "admin" }
  ]
});
print("admin-user created");
'

# Create app user (authenticate as admin first, then create app user on appdb)
kubectl exec -n mongodb mongodb-replica-0 -- mongosh \
  --username admin-user --password admin123password \
  --authenticationDatabase admin \
  --quiet --eval '
db = db.getSiblingDB("appdb");
db.createUser({
  user: "app-user",
  pwd: "app123password",
  roles: [
    { role: "readWrite", db: "appdb" }
  ]
});
print("app-user created on appdb");
'

# Check replica set status: confirm PRIMARY + 2 SECONDARYs
kubectl exec -n mongodb mongodb-replica-0 -- mongosh \
  --username admin-user --password admin123password \
  --authenticationDatabase admin \
  --quiet --eval '
const s = rs.status();
print("Replica set name:", s.set);
s.members.forEach(m => print("  " + m.name + "  state:", m.stateStr));
'

# Test: write data as app-user, then read it back
kubectl exec -n mongodb mongodb-replica-0 -- mongosh \
  --username app-user --password app123password \
  --authenticationDatabase appdb \
  --quiet --eval '
db = db.getSiblingDB("appdb");
db.test_collection.insertOne({ message: "hello from karma", ts: new Date() });
const doc = db.test_collection.findOne({ message: "hello from karma" });
print("Write+Read OK — doc:", JSON.stringify(doc));
db.test_collection.drop();
'

